content.query:
let gatewayRequests = materialize(ApiManagementGatewayLogs
| where TimeGenerated {TimeRange}
| where ApiId in~ ('inference-gpt-5-1', 'inference-gpt-4-1-mini')
| project CorrelationId, ApiId, ResponseCode);
let llmPerRequest = ApiManagementGatewayLlmLog
| where TimeGenerated {TimeRange}
| summarize TotalTokens = sum(TotalTokens), LlmRows = count(), RequestMessageChunks = countif(isnotempty(tostring(RequestMessages))), ResponseMessageChunks = countif(isnotempty(tostring(ResponseMessages))) by CorrelationId;
gatewayRequests
| join kind=leftouter llmPerRequest on CorrelationId
| extend Coverage = case(ResponseCode !between (200 .. 299), 'Not expected for non-2xx response', coalesce(TotalTokens, 0) > 0, 'Token telemetry recorded', 'Successful request without token telemetry')
| summarize Requests = count(), TotalTokens = sum(coalesce(TotalTokens, 0)), LlmRows = sum(coalesce(LlmRows, 0)), RequestMessageChunks = sum(coalesce(RequestMessageChunks, 0)), ResponseMessageChunks = sum(coalesce(ResponseMessageChunks, 0)) by ApiId, Coverage
| order by ApiId asc, Coverage asc
